	/** Augintinis + nuosavybes patikra. */
	private static function pet( $pet_id ){
		global $wpdb; $pf=$wpdb->prefix;
		$row = $wpdb->get_row( $wpdb->prepare(
			"SELECT * FROM {$pf}ps_pets WHERE id=%d AND deleted_at IS NULL LIMIT 1", (int)$pet_id ) );
		if ( ! $row || (int)$row->user_id !== (int)get_current_user_id() ) return null;
		return $row;
	}

